import {
  Body,
  Controller,
  Delete,
  Get,
  Param,
  ParseUUIDPipe,
  Post,
  UseGuards,
} from '@nestjs/common';
import { ApiTags } from '@nestjs/swagger';
import {
  AddItemRequest,
  AddItemRequestSchema,
  CreateSessionRequest,
  CreateSessionRequestSchema,
} from '@smartcart/shared-types';
import {
  AuthenticatedUser,
  CurrentUser,
} from '../../../../common/decorators/current-user.decorator';
import { Roles } from '../../../../common/decorators/roles.decorator';
import { JwtAuthGuard } from '../../../../common/guards/jwt-auth.guard';
import { ResourceOwnershipGuard } from '../../../../common/guards/resource-ownership.guard';
import { RolesGuard } from '../../../../common/guards/roles.guard';
import { ZodValidationPipe } from '../../../../common/pipes/zod-validation.pipe';
import { CheckoutService } from '../../application/services/checkout.service';

/**
 * Session lifecycle endpoints (README §2.4 / §2.8 Workflow 4).
 * Guard stack applied at the class level so new routes inherit it (README §2.5 A01).
 */
@ApiTags('sessions')
@Controller('sessions')
@UseGuards(JwtAuthGuard, RolesGuard)
@Roles('USER')
export class SessionController {
  constructor(private readonly checkout: CheckoutService) {}

  @Post()
  create(
    @CurrentUser() user: AuthenticatedUser,
    @Body(new ZodValidationPipe(CreateSessionRequestSchema))
    dto: CreateSessionRequest,
  ) {
    return this.checkout.createSession(user.sub, dto.storeId);
  }

  @Get('active')
  active(@CurrentUser() user: AuthenticatedUser) {
    return this.checkout.getActiveSession(user.sub);
  }

  @Get(':id')
  @UseGuards(ResourceOwnershipGuard)
  get(
    @CurrentUser() user: AuthenticatedUser,
    @Param('id', ParseUUIDPipe) id: string,
  ) {
    return this.checkout.getSession(id, user.sub);
  }

  @Post(':id/items')
  @UseGuards(ResourceOwnershipGuard)
  addItem(
    @CurrentUser() user: AuthenticatedUser,
    @Param('id', ParseUUIDPipe) id: string,
    @Body(new ZodValidationPipe(AddItemRequestSchema)) dto: AddItemRequest,
  ) {
    return this.checkout.addItem(id, user.sub, dto);
  }

  @Delete(':id/items/:itemId')
  @UseGuards(ResourceOwnershipGuard)
  removeItem(
    @CurrentUser() user: AuthenticatedUser,
    @Param('id', ParseUUIDPipe) id: string,
    @Param('itemId', ParseUUIDPipe) itemId: string,
  ) {
    return this.checkout.removeItem(id, user.sub, itemId);
  }
}
